import { type PropsWithChildren, type ReactElement } from 'react';

import { AnnotationsIconImagesContext } from '../../../contexts/AnnotationsIconImages.context.js';
import { useBuildIconsDataUri } from '../hooks/use-build-icons-data-uri.js';

interface CanvasSvgToImagesProviderProps {
  icons: Array<[ReactElement, string]>;
}

export const CanvasSvgToImagesProvider = ({
  icons,
  children,
}: PropsWithChildren<CanvasSvgToImagesProviderProps>) => {
  const iconsDataUris = useBuildIconsDataUri(icons);
  return (
    <AnnotationsIconImagesContext.Provider value={iconsDataUris}>
      {children}
    </AnnotationsIconImagesContext.Provider>
  );
};

CanvasSvgToImagesProvider['displayName'] = 'CanvasSvgToImagesProvider';
